import{_ as a,c as e,o as i,a4 as r}from"./chunks/framework.CzsDe1xi.js";const g=JSON.parse('{"title":"Spring面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"doc/编程语言/后端/Java/draft/Spring面试问题.md","filePath":"packages/doc/src/编程语言/后端/Java/draft/Spring面试问题.md","lastUpdated":1711551906000}'),l={name:"doc/编程语言/后端/Java/draft/Spring面试问题.md"},n=r('<h1 id="spring面试问题" tabindex="-1">Spring面试问题 <a class="header-anchor" href="#spring面试问题" aria-label="Permalink to &quot;Spring面试问题&quot;">​</a></h1><h2 id="_1-autowired和-resource区别" tabindex="-1">1.@Autowired和@Resource区别? <a class="header-anchor" href="#_1-autowired和-resource区别" aria-label="Permalink to &quot;1.@Autowired和@Resource区别?&quot;">​</a></h2><h4 id="autowired" tabindex="-1">@Autowired <a class="header-anchor" href="#autowired" aria-label="Permalink to &quot;@Autowired&quot;">​</a></h4><ul><li>@AutoWired是spring中注解，主要是使用类型来进行注入</li><li>注解是按类型装配依赖对象，默认情况下它要求依赖对象必须存在，如果允许null值，可以设置它required属性为false。</li><li>@AutoWired不支持基于name注入，如果需要准确定位bean注入，需要与@Qualifier配合使用</li></ul><h4 id="resource" tabindex="-1">@Resource <a class="header-anchor" href="#resource" aria-label="Permalink to &quot;@Resource&quot;">​</a></h4><ul><li>@Resource是JDK1.6支持的注解，默认使用名称进行注入，如果没有匹配到name属性指定，则使用类型注入。<strong>@Resource虽然是JDK原生支持的，但是注解处理器是Spring提供</strong></li><li>@Resource默认使用name属性注入，使用注解时可以指定name属性，如果没指定该属性，则根据注解位置情况使用字段名或者属性名（setter)注入</li><li>@Resource根据name属性无法注入时，会使用类型进行注入。但是一旦指定name属性，则不会再使用name属性注入</li></ul><h4 id="spring两种注入类型" tabindex="-1">Spring两种注入类型 <a class="header-anchor" href="#spring两种注入类型" aria-label="Permalink to &quot;Spring两种注入类型&quot;">​</a></h4><ul><li>byName:通过参数名自动注入，如果一个bean的name与另一个bean的property相同，就自动注入</li><li>byType:通过参数的数据类型自动注入，如果一个bean的数据类型与另外一个bean的property属性的数据类型兼容，就自动注入</li></ul><h2 id="_2-spring循环依赖如何解决" tabindex="-1">2.Spring循环依赖如何解决？ <a class="header-anchor" href="#_2-spring循环依赖如何解决" aria-label="Permalink to &quot;2.Spring循环依赖如何解决？&quot;">​</a></h2><p>循环依赖问题在Spring中主要有三种情况：</p><ul><li>通过构造方法进行依赖注入时产生的循环依赖问题。</li><li>通过setter方法进行依赖注入且是在多例（原型）模式下产生的循环依赖问题。</li><li>通过setter方法进行依赖注入且是在单例模式下产生的循环依赖问题。</li></ul><p>注意：在Spring中，只有【第三种方式】的循环依赖问题被解决了，其他两种方式在遇到循环依赖问题时都会产生异常。</p><p>其实也很好解释:</p><ul><li>第一种构造方法注入的情况下，在new对象的时候就会堵塞住了，其实也就是”先有鸡还是先有蛋“的历史难题。</li><li>第二种setter方法&amp;&amp;多例的情况下，每一次getBean()时，都会产生一个新的Bean，如此反复下去就会有无穷无尽的Bean产生了，最终就会导致OOM问题的出现。</li></ul><p>Spring中有三个缓存，用于存储单例的Bean实例，这三个缓存是彼此互斥的，不会针对同一个Bean的实例同时存储。</p><p>如果调用getBean，则需要从三个缓存中依次获取指定的Bean实例。读取顺序依次是一级缓存--&gt;二级缓存--&gt;三级缓存</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>一级缓存：Map&lt;String, Object&gt; singletonObjects</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="第一级缓存的作用" tabindex="-1">第一级缓存的作用？ <a class="header-anchor" href="#第一级缓存的作用" aria-label="Permalink to &quot;第一级缓存的作用？&quot;">​</a></h3><ul><li>用于存储单例模式下创建的Bean实例（已经创建完毕）。</li><li>该缓存是对外使用的，指的就是使用Spring框架的程序员。</li></ul><h3 id="存储什么数据" tabindex="-1">存储什么数据？ <a class="header-anchor" href="#存储什么数据" aria-label="Permalink to &quot;存储什么数据？&quot;">​</a></h3><ul><li>K：bean的名称</li><li>V：bean的实例对象（有代理对象则指的是代理对象，已经创建完毕）</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>第二级缓存：Map&lt;String, Object&gt; earlySingletonObjects</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="第二级缓存的作用" tabindex="-1">第二级缓存的作用？ <a class="header-anchor" href="#第二级缓存的作用" aria-label="Permalink to &quot;第二级缓存的作用？&quot;">​</a></h3><ul><li>用于存储单例模式下创建的Bean实例（该Bean被提前暴露的引用,该Bean还在创建中）。</li><li>该缓存是对内使用的，指的就是Spring框架内部逻辑使用该缓存。</li><li>为了解决第一个classA引用最终如何替换为代理对象的问题（如果有代理对象）请爬楼参考演示案例</li></ul><h3 id="存储什么数据-1" tabindex="-1">存储什么数据？ <a class="header-anchor" href="#存储什么数据-1" aria-label="Permalink to &quot;存储什么数据？&quot;">​</a></h3><ul><li>K：bean的名称</li><li>V：bean的实例对象（有代理对象则指的是代理对象，该Bean还在创建中）</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>第三级缓存：Map&lt;String, ObjectFactory&lt;?&gt;&gt; singletonFactories</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="第三级缓存的作用" tabindex="-1">第三级缓存的作用？ <a class="header-anchor" href="#第三级缓存的作用" aria-label="Permalink to &quot;第三级缓存的作用？&quot;">​</a></h3><p>通过ObjectFactory对象来存储单例模式下提前暴露的Bean实例的引用（正在创建中）。该缓存是对内使用的，指的就是Spring框架内部逻辑使用该缓存。此缓存是解决循环依赖最大的功臣</p><h3 id="存储什么数据-2" tabindex="-1">存储什么数据？ <a class="header-anchor" href="#存储什么数据-2" aria-label="Permalink to &quot;存储什么数据？&quot;">​</a></h3><ul><li>K：bean的名称</li><li>V：ObjectFactory，该对象持有提前暴露的bean的引用</li></ul><p>为什么第三级缓存要使用ObjectFactory？需要提前产生代理对象。</p><p>什么时候将Bean的引用提前暴露给第三级缓存的ObjectFactory持有？时机就是在第一步实例化之后，第二步依赖注入之前，完成此操作。</p><h2 id="_3" tabindex="-1">3. <a class="header-anchor" href="#_3" aria-label="Permalink to &quot;3.&quot;">​</a></h2>',34),t=[n];function s(o,p,c,d,u,h){return i(),e("div",null,t)}const m=a(l,[["render",s]]);export{g as __pageData,m as default};
